	/* OrderNisCnlSendMapper.xml updateOrderNisCnlSuccResult */
    UPDATE TORDER_INFO_SO_HD SET 
    NISSNDYN ='Y'
    , UPDATEDATE = TO_CHAR(CURRENT_TIMESTAMP,'YYYYMMDDHH24MISS')
    , UPDATEURKEY = #{interfaceUrkey}
    WHERE 1 = 1
      AND OWKEY = #{owkey} 
      AND SOHDKEY = #{sohdkey}
      AND NISYN = 'Y'
      AND NISSNDYN ='N'
